// MeasureLatency pings the specified host the given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build ping command arguments based on the operating system
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		// Linux, macOS, and other Unix-like systems use -c
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from ping command output.
// It supports Unix-like systems (Linux/macOS) and Windows.
func parsePingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")

