func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than zero")
	}

	// Set a timeout to prevent hanging on unreachable hosts
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.CommandContext(ctx, "ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.CommandContext(ctx, "ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	latencies := extractLatencies(string(output))
	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	var sum float64
	for _, lat := range latencies {
		sum += lat
	}

	return sum / float64(len(latencies)), nil
}

// extractLatencies parses ping command output and extracts individual latency values.
func extractLatencies(output string) []float64 {
	var latencies []float64
	lines := strings.Split(output, "\n")

	for _, line := range lines {
		// Look for lines containing "time=" and " ms"
		if !strings.Contains(line, "time=") || !strings.Contains(line, " ms") {
			continue
		}

		// Extract the value between "time=" and " ms"
		timeIdx := strings.Index(line, "time=")
		if timeIdx == -1 {
			continue
		}
		start := timeIdx + len("time=")

		msIdx := strings.Index(line[start:], " ms")
		if msIdx == -1 {
			continue
		}

		timeStr := strings.TrimSpace(line[start : start+msIdx])
		if val, err := strconv.ParseFloat(timeStr, 64); err == nil {
			latencies = append(latencies, val)
		}
	}

	return latencies
}

