package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems use -c
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts individual ping times from the command output and calculates the average.
func parsePingOutput(output string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))
	var sum float64
	var validPings int

	for scanner.Scan() {
		line := scanner.Text()
		// Look for "time=" which appears in both Unix and Windows ping outputs
		if idx := strings.Index(line, "time="); idx != -1 {
			rest := line[idx+5:]
			// Find the end of the numeric value (stop at first non-digit/non-dot character)
			endIdx := strings.IndexFunc(rest, func(r rune) bool {
				return (r < '0' || r > '9') && r != '.'
			})
			if endIdx == -1 {
				endIdx = len(rest)
			}

			timeStr := rest[:endIdx]
			if latency, err := strconv.ParseFloat(timeStr, 64); err == nil {
				sum += latency
				validPings++
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if validPings == 0 {
		return 0, fmt.Errorf("no valid latency measurements found in output")
	}

	return sum / float64(validPings), nil
}

func main() {
	// Example usage
	latency, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", latency)
}

