func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Parse based on OS
	if runtime.GOOS == "windows" {
		// Windows format: Average = 0ms
		re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) >= 2 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency: %w", err)
			}
			return avg, nil
		}
	} else {
		// Unix-like format: rtt min/avg/max/mdev = 0.023/0.045/0.067/0.018 ms
		// or round-trip min/avg/max/stddev = ...
		re := regexp.MustCompile(`(?:rtt|round-trip).*=\s*[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+\s*ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) >= 2 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency: %w", err)
			}
			return avg, nil
		}

		// Fallback: calculate average from individual time values
		// Look for patterns like "time=0.042 ms" or "time=0.042"
		re = regexp.MustCompile(`time=([\d\.]+)\s*ms?`)
		allMatches := re.FindAllStringSubmatch(outputStr, -1)
		if len(allMatches) > 0 {
			var sum float64
			validCount := 0
			for _, match := range allMatches {
				if len(match) >= 2 {
					val, err := strconv.ParseFloat(match[1], 64)
					if err != nil {
						continue
					}
					sum += val
					validCount++
				}
			}
			if validCount > 0 {
				return sum / float64(validCount), nil
			}
		}
	}

	return 0, fmt.Errorf("could not parse ping output to determine average latency")
