package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// If there's no output and there was an error, return the error
	if len(output) == 0 && err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	// Check for complete packet loss or unreachable host
	lowerOutput := strings.ToLower(outputStr)
	if strings.Contains(lowerOutput, "100% packet loss") || 
	   strings.Contains(lowerOutput, "100% loss") ||
	   strings.Contains(lowerOutput, "could not find host") ||
	   strings.Contains(lowerOutput, "unknown host") ||
	   strings.Contains(lowerOutput, "ping request could not find host") {
		return 0, fmt.Errorf("host unreachable or 100%% packet loss")
	}

	var avg float64
	var parseErr error

	if runtime.GOOS == "windows" {
		avg, parseErr = parseWindowsOutput(outputStr)
	} else {
		avg, parseErr = parseUnixOutput(outputStr)
	}

	if parseErr != nil {
		return 0, parseErr
	}

	return avg, nil
}

func parseWindowsOutput(output string) (float64, error) {
	// Windows format: "Average = Xms" or "Average = X.XXms"
	re := regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)\s*ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	return 0, fmt.Errorf("could not parse average latency from ping output")
}

func parseUnixOutput(output string) (float64, error) {
	// Unix format: "min/avg/max/mdev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
	// or: "round-trip min/avg/max/stddev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
	re := regexp.MustCompile(`min/avg/max(?:/mdev|/stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+`)
	matches := re.FindStringSubmatch(output)
	if len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	return 0, fmt.Errorf("could not parse average latency from ping output")
}

func main() {
	// Example usage
	latency, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", latency)
}

