// MeasureLatency pings the specified host the given number of times and returns
// the average round-trip time in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	var cmd *exec.Cmd

	// Determine ping command arguments based on OS
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	outputStr := string(output)
	var avgLatency float64
	found := false

	if runtime.GOOS == "windows" {
		// Windows format: "Average = 24ms" or "Average = 0ms"
		scanner := bufio.NewScanner(strings.NewReader(outputStr))
		for scanner.Scan() {
			line := strings.TrimSpace(scanner.Text())
			if strings.Contains(line, "Average") && strings.Contains(line, "=") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
					valStr := strings.TrimSpace(parts[1])
					valStr = strings.TrimSuffix(valStr, "ms")
					val, err := strconv.ParseFloat(valStr, 64)
					if err == nil {
						avgLatency = val
						found = true
						break
					}
				}
			}
		}
	} else {
		// Unix-like format: "rtt min/avg/max/mdev = 24.123/25.456/26.789/0.123 ms"
		// or "round-trip min/avg/max/stddev = 24.892/25.059/25.234/0.123 ms"
		scanner := bufio.NewScanner(strings.NewReader(outputStr))
		for scanner.Scan() {
			line := scanner.Text()
			if strings.Contains(line, "avg") && strings.Contains(line, "=") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
					stats := strings.TrimSpace(parts[1])
					// Remove "ms" suffix if present
					stats = strings.TrimSuffix(stats, " ms")
					values := strings.Split(stats, "/")
					if len(values) >= 2 {
						avgStr := values[1]
						val, err := strconv.ParseFloat(avgStr, 64)
						if err == nil {
							avgLatency = val
							found = true
							break
						}
					}
				}
			}
		}
	}

	if !found {
		return 0, fmt.Errorf("could not parse ping output to determine average latency")
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency to %s: %v\n", host, err)
		return
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, avg)
}

