package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Ping may return non-zero exit code on packet loss, but we might still have valid output
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
	}

	// Regex to match time values in ping output
	// Matches patterns like: time=12.3 ms, time=12ms, time<1ms, time:12ms
	re := regexp.MustCompile(`time[=:<]([0-9.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency measurements found in ping output")
	}

	var sum float64
	var validCount int
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		sum += val
		validCount++
	}

	if validCount == 0 {
		return 0, fmt.Errorf("no valid latency measurements parsed")
	}

	average := sum / float64(validCount)
	return average, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

