package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Regex to match time values in ping output
	// Handles: time=12.3 ms, time=12ms, time<1ms, etc.
	re := regexp.MustCompile(`time[=:]([<]?[\d\.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	var total float64
	var validCount int

	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		timeStr := match[1]
		// Handle "<1ms" case (Windows)
		if strings.HasPrefix(timeStr, "<") {
			timeStr = timeStr[1:]
		}

		val, err := strconv.ParseFloat(timeStr, 64)
		if err != nil {
			continue
		}
		total += val
		validCount++
	}

	if validCount == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	average := total / float64(validCount)
	return average, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", host, count)

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", latency)
}

