package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build command with proper arguments to avoid shell injection vulnerabilities
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, BSD, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Look for the line containing RTT statistics
	// Linux format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS format: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	// Windows format: Average = 23ms

	var avg float64
	found := false

	// Try Unix-like format (Linux/macOS)
	lines := strings.Split(outputStr, "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			// Extract average latency using regex
			// Matches: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
			// Or: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
			re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max(?:/mdev|/stddev)? = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				avgStr := matches[1]
				parsedAvg, err := strconv.ParseFloat(avgStr, 64)
				if err == nil {
					avg = parsedAvg
					found = true
					break
				}
			}
		}
	}

	// Try Windows format if not found
	if !found && runtime.GOOS == "windows" {
		// Windows typically shows: Minimum = Xms, Maximum = Yms, Average = Zms
		reWin := regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)\s*ms`)
		matches := reWin.FindStringSubmatch(outputStr)
		if len(matches) >= 2 {
			avgStr := matches[1]
			parsedAvg, err := strconv.ParseFloat(avgStr, 64)
			if err == nil {
				avg = parsedAvg
				found = true
			}
		}
	}

	if !found {
		return 0, errors.New("could not find or parse RTT statistics in ping output")
	}

	return avg, nil
}

