package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		if len(output) == 0 {
			return 0, fmt.Errorf("ping command failed: %w", err)
		}
	}

	return parsePingOutput(string(output))
}

func parsePingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	for _, line := range lines {
		if strings.Contains(line, "avg") || strings.Contains(line, "/") {
			re := regexp.MustCompile(`(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 3 {
				avg, err := strconv.ParseFloat(matches[2], 64)
				if err == nil {
					return avg, nil
				}
			}
		}
	}

	for _, line := range lines {
		lower := strings.ToLower(line)
		if strings.Contains(lower, "average") {
			re := regexp.MustCompile(`average\s*[=:]\s*(\d+(?:\.\d+)?)\s*ms`)
			matches := re.FindStringSubmatch(lower)
			if len(matches) > 1 {
				return strconv.ParseFloat(matches[1], 64)
			}
		}
	}

	var total float64
	var validCount int
	timeRe := regexp.MustCompile(`time[<=](\d+(?:\.\d+)?)\s*ms`)

	for _, line := range lines {
		matches := timeRe.FindStringSubmatch(line)
		if len(matches) > 1 {
			t, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				total += t
				validCount++
			}
		}
	}

	if validCount > 0 {
		return total / float64(validCount), nil
	}

	return 0, fmt.Errorf("unable to parse ping output")
}

func main() {
	latency, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", latency)
}

