		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute ping command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Parse output based on OS
	if runtime.GOOS == "windows" {
		// Windows format: "Average = 24ms" or "Average = 24.5ms"
		re := regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)\s*ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse ping output: %s", outputStr)
		}
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	} else {
