	}
	return parseUnixPing(outputStr)
}

// parseUnixPing parses the average latency from ping output on Linux/macOS.
// Expected format: rtt min/avg/max/mdev = 20.123/25.456/30.789/2.345 ms
func parseUnixPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		// Look for lines containing statistics (rtt or round-trip)
		if strings.Contains(line, "min/avg/max") || strings.Contains(line, "rtt") {
			parts := strings.Split(line, "=")
			if len(parts) >= 2 {
				// Extract values part: " 20.123/25.456/30.789/2.345 ms"
				valuesStr := strings.TrimSpace(parts[1])
				// Remove "ms" suffix if present
				valuesStr = strings.TrimSuffix(valuesStr, "ms")
				valuesStr = strings.TrimSpace(valuesStr)

				values := strings.Split(valuesStr, "/")
				if len(values) >= 2 {
