	if runtime.GOOS == "windows" {
		// Windows format: "Minimum = Xms, Maximum = Yms, Average = Zms"
		// or "Minimum = X ms, Maximum = Y ms, Average = Z ms"
		lines := strings.Split(outputStr, "\n")
		for _, line := range lines {
			if strings.Contains(line, "Average") {
				idx := strings.Index(line, "Average = ")
				if idx != -1 {
					timePart := line[idx+len("Average = "):]
					// Remove "ms" suffix and trim spaces
					timePart = strings.TrimSpace(timePart)
					timePart = strings.TrimSuffix(timePart, "ms")
					timePart = strings.TrimSpace(timePart)
					avg, err := strconv.ParseFloat(timePart, 64)
