// parsePingOutput extracts the average latency from ping command output.
// It handles both Windows and Unix-like (Linux/macOS) output formats.
func parsePingOutput(output string, os string) (float64, error) {
	lines := strings.Split(output, "\n")

	if os == "windows" {
		// Windows format: "Minimum = Xms, Maximum = Yms, Average = Zms"
		for _, line := range lines {
			if strings.Contains(line, "Average") && strings.Contains(line, "=") {
				parts := strings.Split(line, ",")
				for _, part := range parts {
					if strings.Contains(part, "Average") {
						start := strings.Index(part, "=")
						if start != -1 {
							valueStr := strings.TrimSpace(part[start+1:])
							valueStr = strings.TrimSuffix(valueStr, "ms")
							value, err := strconv.ParseFloat(strings.TrimSpace(valueStr), 64)
							if err != nil {
								return 0, fmt.Errorf("failed to parse average latency: %w", err)
							}
							return value, nil
						}
					}
				}
			}
		}
	} else {
		// Unix format: "round-trip min/avg/max/stddev = X/Y/Z/W ms"
		// or "rtt min/avg/max/mdev = X/Y/Z/W ms"
		for _, line := range lines {
			lowerLine := strings.ToLower(line)
			if (strings.Contains(lowerLine, "avg") || strings.Contains(lowerLine, "rtt")) && strings.Contains(line, "=") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
