// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system's ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	err := cmd.Run()
	if err != nil {
		// Ping may return non-zero exit code if packets are lost,
		// but we might still have valid output to parse
		if out.Len() == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
	}

	return parseAverageLatency(out.String())
}

// parseAverageLatency extracts the average latency from ping command output.
// It supports both Windows and Unix (Linux/macOS) output formats.
func parseAverageLatency(output string) (float64, error) {
	// Windows format: "Minimum = Xms, Maximum = Yms, Average = Zms"
	windowsRe := regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)\s*ms`)
	if matches := windowsRe.FindStringSubmatch(output); matches != nil {
		return strconv.ParseFloat(matches[1], 64)
	}

	// Unix format: "round-trip min/avg/max/stddev = X/Y/Z/W ms" or "rtt min/avg/max/mdev = X/Y/Z/W ms"
	unixRe := regexp.MustCompile(`(?:round-trip|rtt)\s+min/avg/max/(?:stddev|mdev)\s*=\s*[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+\s*ms`)
	if matches := unixRe.FindStringSubmatch(output); matches != nil {
		return strconv.ParseFloat(matches[1], 64)
	}

