	if len(matches) > 0 {
		var total float64
		for _, match := range matches {
			val, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			total += val
		}
		return total / float64(len(matches)), nil
	}

	return 0, fmt.Errorf("could not parse latency from ping output")
}

