package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		count = 4
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output))
}

func parsePingOutput(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		return parseWindowsOutput(output)
	}
	return parseUnixOutput(output)
}

func parseWindowsOutput(output string) (float64, error) {
	// Look for summary line: "Average = Xms"
	re := regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)\s*ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	// Fallback: parse individual times (time=1ms or time<1ms)
	re = regexp.MustCompile(`time[<=](\d+(?:\.\d+)?)ms`)
	return calculateAverageFromMatches(re, output)
}

func parseUnixOutput(output string) (float64, error) {
	// Look for summary: "min/avg/max/stddev = X/Y/Z/W ms" or "rtt min/avg/max/mdev"
	re := regexp.MustCompile(`[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	// Fallback: parse individual times (time=12.3 ms)
	re = regexp.MustCompile(`time=([\d.]+)\s*ms`)
	return calculateAverageFromMatches(re, output)
}

func calculateAverageFromMatches(re *regexp.Regexp, output string) (float64, error) {
	matches := re.FindAllStringSubmatch(output, -1)
	if len(matches) == 0 {
		return 0, fmt.Errorf("could not parse ping output")
	}

	var total float64
	var count int
	for _, match := range matches {
		if len(match) > 1 {
			val, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			total += val
			count++
		}
	}

	if count == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	return total / float64(count), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

