package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	// Windows uses -n for count, Unix-like systems (Linux, macOS) use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	return parsePingOutput(string(output))
}

// parsePingOutput parses the output of the ping command and calculates the average latency.
func parsePingOutput(output string) (float64, error) {
	var totalLatency float64
	var successfulPings int

	scanner := bufio.NewScanner(strings.NewReader(output))
	for scanner.Scan() {
		line := strings.ToLower(scanner.Text())

		// Look for time= in the line (handles both "time=0.123 ms" and "time=1ms")
		if idx := strings.Index(line, "time="); idx != -1 {
			timePart := line[idx+5:]

			// Handle Windows' "time<1ms" format
			if strings.HasPrefix(timePart, "<") {
				timePart = timePart[1:]
			}

			// Extract the numeric value before "ms"
			if msIdx := strings.Index(timePart, "ms"); msIdx != -1 {
				timeStr := strings.TrimSpace(timePart[:msIdx])
				if latency, err := strconv.ParseFloat(timeStr, 64); err == nil {
					totalLatency += latency
					successfulPings++
				}
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error parsing ping output: %w", err)
	}

	if successfulPings == 0 {
		return 0, fmt.Errorf("no successful ping responses found")
	}

	average := totalLatency / float64(successfulPings)
	return average, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s (%d attempts): %.2f ms\n", host, count, avg)
}

