package main

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w, output: %s", err, string(output))
	}

	return parseAverageLatency(string(output), runtime.GOOS)
}

// parseAverageLatency extracts the average latency from ping output
func parseAverageLatency(output string, osType string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))

	// Strategy 1: Try to parse individual time values and calculate average
	var sum float64
	var validPings int

	for scanner.Scan() {
		line := scanner.Text()
		lineLower := strings.ToLower(line)

		// Look for time=XXms or time=XX.Xms
		if idx := strings.Index(lineLower, "time="); idx != -1 {
			timePart := line[idx+5:] // Skip "time="

			// Find the end of the number
			endIdx := strings.IndexAny(timePart, " \t\r\nms")
			if endIdx == -1 {
				endIdx = len(timePart)
			}

			timeStr := strings.TrimSpace(timePart[:endIdx])

			// Handle cases like "<1" or ">100"
			timeStr = strings.TrimPrefix(timeStr, "<")
			timeStr = strings.TrimPrefix(timeStr, ">")

			if val, err := strconv.ParseFloat(timeStr, 64); err == nil {
				sum += val
				validPings++
			}
		}
	}

	if validPings > 0 {
		return sum / float64(validPings), nil
	}

	// Strategy 2: Parse summary statistics
	return parseSummaryStatistics(output, osType)
}

// parseSummaryStatistics extracts average from the summary line
func parseSummaryStatistics(output string, osType string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))

	for scanner.Scan() {
		line := scanner.Text()
		lineLower := strings.ToLower(line)

		if osType == "windows" {
			// Windows: "Minimum = Xms, Maximum = Yms, Average = Zms"
			if strings.Contains(lineLower, "average") && strings.Contains(line, "=") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
					avgStr := strings.TrimSpace(parts[len(parts)-1])
					avgStr = strings.TrimSuffix(strings.ToLower(avgStr), "ms")
					avgStr = strings.TrimSpace(avgStr)
					return strconv.ParseFloat(avgStr, 64)
				}
			}
		} else {
			// Unix: "rtt min/avg/max/mdev = X/Y/Z/W ms" or "round-trip min/avg/max/stddev = X/Y/Z/W ms"
			if (strings.Contains(lineLower, "rtt") || strings.Contains(lineLower, "round-trip")) && 
			   strings.Contains(line, "=") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
					stats := strings.TrimSpace(parts[1])
					stats = strings.TrimSuffix(strings.ToLower(stats), "ms")
					stats = strings.TrimSpace(stats)

					// Split by "/" to get min, avg, max, stddev
					values := strings.Split(stats, "/")
					if len(values) >= 2 {
						return strconv.ParseFloat(values[1], 64)
					}
				}
			}
		}
	}

	return 0, fmt.Errorf("unable to parse ping output to determine average latency")
}

func main() {
	// Example usage and basic CLI interface
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "Example: %s google.com 4\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid count '%s': %v\n", os.Args[2], err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

