package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	var cmd *exec.Cmd

	// Adjust ping arguments based on OS
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		// Default to Unix-style flags
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output), runtime.GOOS)
}

func parsePingOutput(output string, os string) (float64, error) {
	lines := strings.Split(output, "\n")

	// First try to extract from summary statistics
	for _, line := range lines {
		line = strings.TrimSpace(line)

		if os == "windows" {
			// Windows format: Average = Xms
			if strings.Contains(line, "Average") {
				re := regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)ms`)
				matches := re.FindStringSubmatch(line)
				if len(matches) > 1 {
					return strconv.ParseFloat(matches[1], 64)
				}
			}
		} else {
			// Unix format: min/avg/max/stddev = X/Y/Z/W ms
			if strings.Contains(line, "avg") || (strings.Contains(line, "/") && strings.Contains(line, "ms")) {
				re := regexp.MustCompile(`[\d\.]+/([\d\.]+)/[\d\.]+`)
				matches := re.FindStringSubmatch(line)
				if len(matches) > 1 {
					return strconv.ParseFloat(matches[1], 64)
				}
			}
		}
	}

	// Fallback: calculate average from individual response times
	var times []float64
	// Match time=XXms or time=XX.Xms or time=XX ms
	timeRegex := regexp.MustCompile(`time[=:](\d+(?:\.\d+)?)\s*ms`)

	for _, line := range lines {
		matches := timeRegex.FindStringSubmatch(line)
		if len(matches) > 1 {
			if t, err := strconv.ParseFloat(matches[1], 64); err == nil {
				times = append(times, t)
			}
		}
	}

	if len(times) == 0 {
		return 0, fmt.Errorf("no successful ping responses found in output")
	}

	var sum float64
	for _, t := range times {
		sum += t
	}

	return sum / float64(len(times)), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Failed to measure latency to %s: %v\n", host, err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

