package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times
// and returns the average latency in milliseconds.
// It uses the system ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	return parsePingOutput(string(output), runtime.GOOS)
}

func parsePingOutput(output, goos string) (float64, error) {
	var times []float64
	scanner := bufio.NewScanner(strings.NewReader(output))

	for scanner.Scan() {
		line := scanner.Text()
		time, found := extractTime(line, goos)
		if found {
			times = append(times, time)
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if len(times) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	var sum float64
	for _, t := range times {
		sum += t
	}
	return sum / float64(len(times)), nil
}

func extractTime(line, goos string) (float64, bool) {
	if goos == "windows" {
		// Windows formats: "time<1ms" or "time=24ms"
		if strings.Contains(line, "time<1ms") {
			return 0.5, true // approximate for <1ms
		}
		const prefix = "time="
		idx := strings.Index(line, prefix)
		if idx == -1 {
			return 0, false
		}
		rest := line[idx+len(prefix):]
		endIdx := strings.Index(rest, "ms")
		if endIdx == -1 {
			return 0, false
		}
		val, err := strconv.ParseFloat(rest[:endIdx], 64)
		if err != nil {
			return 0, false
		}
		return val, true
	}

	// Unix-like (Linux, macOS): format "time=24.3 ms"
	const prefix = "time="
	idx := strings.Index(line, prefix)
	if idx == -1 {
		return 0, false
	}
	rest := line[idx+len(prefix):]
	endIdx := strings.Index(rest, " ms")
	if endIdx == -1 {
		return 0, false
	}
	val, err := strconv.ParseFloat(rest[:endIdx], 64)
	if err != nil {
		return 0, false
	}
	return val, true
}

func main() {
	// Example usage
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

